def solve(roles, search_term):
    if not roles or not search_term:
        return []

    search_term = search_term.lower()
    filtered_roles = []

    for role in roles:
        if search_term in role['name'].lower():
            filtered_roles.append(role)
        elif search_term in role['created_by'].lower():
            filtered_roles.append(role)

    return filtered_roles
